import classNames from 'classnames';
import styles from './home-info.module.scss';
import { ButtonWrap } from '../button-wrap/button-wrap';
import { Button } from '../button/button';

export interface HomeInfoProps {
    className?: string;
}

/**
 * This component was created using Codux's Default new component template.
 * To create custom component templates, see https://help.codux.com/kb/en/article/kb16522
 */
export const MomentHomeInfo = ({ className }: HomeInfoProps) => {
    return <div className={styles['home-info-wrap']}>
        <div className="info">
            <h1 className={styles.h1}>Casey<br />&amp;Peter</h1>
            <p className={styles['home-info__p']}>Cum sociis natoque penatibus et magnis dis parturient montes, nascetur ridiculus mus.</p>
            <ButtonWrap >
                <Button ico="play" label="Relive" />
                <Button label="Explore" className="button--outline" ico={'folder'} />
            </ButtonWrap>
        </div></div>;
};
